# GIF is natively supported by tk.PhotoImage (no Pillow needed)
_LOGO_GIF_B64 = ""
# PNG fallback used when Pillow is available (better quality)
_LOGO_PNG_B64 = ""
_PDF_B64 = ""

def _load_logo():
    """Load logo — GIF works without Pillow; PNG used if Pillow available."""
    try:
        from PIL import Image, ImageTk
        raw = base64.b64decode(_LOGO_PNG_B64)
        img = Image.open(io.BytesIO(raw)).resize((70, 70), Image.LANCZOS)
        ph = ImageTk.PhotoImage(img)
        return ph
    except Exception:
        pass
    try:
        # tk.PhotoImage supports GIF natively — NO Pillow needed
        ph = tk.PhotoImage(data=_LOGO_GIF_B64)
        return ph
    except Exception:
        return None

def open_project_pdf():
    try:
        data = base64.b64decode(_PDF_B64)
        tmp = tempfile.NamedTemporaryFile(delete=False, suffix=".pdf", prefix="TrishulInfo_")
        tmp.write(data); tmp.close()
        if platform.system() == "Windows":   os.startfile(tmp.name)
        elif platform.system() == "Darwin":  subprocess.Popen(["open", tmp.name])
        else:                                subprocess.Popen(["xdg-open", tmp.name])
    except Exception as e:
        messagebox.showerror("PDF Error", f"Could not open PDF:\n{e}")

