# ══════════════════════════════════════════════════════════════
#  ENCRYPTION
# ══════════════════════════════════════════════════════════════
_APP_SALT = b"USBSEC_v4.1_SECURE_STORAGE_2026"
_ENC_KEY = None
def _derive_key():
    try: host=socket.gethostname().encode()
    except: host=b"localhost"
    return hashlib.pbkdf2_hmac("sha256",host,_APP_SALT,100_000,dklen=32)
def _get_key():
    global _ENC_KEY
    if _ENC_KEY is None: _ENC_KEY=_derive_key()
    return _ENC_KEY
def _xor_keystream(data,nonce):
    import hmac as _h
    key=_get_key(); out=bytearray(); block=0
    while len(out)<len(data):
        out.extend(_h.new(key,nonce+struct.pack(">Q",block),"sha256").digest()); block+=1
    return bytes(x^y for x,y in zip(data,out[:len(data)]))
def _encrypt(pt):
    n=os.urandom(16); ct=_xor_keystream(pt.encode("utf-8"),n)
    return base64.b64encode(n+ct).decode("ascii")
def _decrypt(ct):
    raw=base64.b64decode(ct.encode("ascii")); n,c=raw[:16],raw[16:]
    return _xor_keystream(c,n).decode("utf-8")

# ══════════════════════════════════════════════════════════════
#  DATA HELPERS
# ══════════════════════════════════════════════════════════════
def hpw(p): return hashlib.sha256(p.encode()).hexdigest()
def _enc_write(path,d):
    tmp=path+".tmp"; enc=_encrypt(json.dumps(d,indent=2))
    with open(tmp,"w",encoding="ascii") as f: f.write(enc)
    if os.path.exists(path): os.replace(tmp,path)
    else: os.rename(tmp,path)
def _enc_read(path):
    if not os.path.exists(path): return {}
    try:
        with open(path,"r",encoding="utf-8") as f: raw=f.read().strip()
        if not raw: return {}
        try: d=json.loads(_decrypt(raw)); return d if isinstance(d,dict) else {}
        except: d=json.loads(raw); return d if isinstance(d,dict) else {}
    except:
        try:
            import shutil; shutil.copy(path,path+".bak"); os.remove(path)
        except: pass
        return {}
def load():  return _enc_read(USERS_FILE)
def save(d): _enc_write(USERS_FILE,d)
def ltok():  return _enc_read(TOK_FILE)
def stok(t): _enc_write(TOK_FILE,t)
def linv():  return _enc_read(INV_FILE)
def sinv(d): _enc_write(INV_FILE,d)
def _log_enc(line): return _encrypt(line)+"\n"
def _log_dec_all(path):
    if not os.path.exists(path): return ""
    lines=[]
    try:
        with open(path,"r",encoding="ascii") as f:
            for raw in f:
                raw=raw.strip()
                if not raw: continue
                try: lines.append(_decrypt(raw))
                except: lines.append(raw)
    except: pass
    return "\n".join(lines)

