#  LIVE DB
# ══════════════════════════════════════════════════════════════
class _LiveDB(dict):
    def _reload(self):
        try: fresh=load()
        except: fresh={}
        super().clear(); super().update(fresh)
    def __contains__(self,k): self._reload(); return super().__contains__(k)
    def __getitem__(self,k):  self._reload(); return super().__getitem__(k)
    def get(self,k,d=None):   self._reload(); return super().get(k,d)
    def items(self):          self._reload(); return list(super().items())
    def keys(self):           self._reload(); return list(super().keys())
DB=_LiveDB(); DB._reload()

def log(msg,who="SYS"):
    line=f"[{time.strftime('%Y-%m-%d %H:%M:%S')}][{who}] {msg}"
    with open(LOG_FILE,"a",encoding="ascii") as f: f.write(_log_enc(line))

# ══════════════════════════════════════════════════════════════
#  PASSWORD POLICY
# ══════════════════════════════════════════════════════════════
def pw_ok(pw):
    e=[]
    if len(pw)<8: e.append("Min 8 characters")
    if not re.search(r"[A-Z]",pw): e.append("One uppercase letter")
    if not re.search(r"[a-z]",pw): e.append("One lowercase letter")
    if not re.search(r"\d",pw): e.append("One digit")
    if not re.search(r"[!@#$%^&*()\-_=+]",pw): e.append("One special char e.g. !@#$")
    return e

# ══════════════════════════════════════════════════════════════
#  OTP
# ══════════════════════════════════════════════════════════════
_OTP={"c":None,"x":0,"tries":0}
def make_otp():
    code="".join(random.choices(string.digits,k=6))
    _OTP["c"]=code; _OTP["x"]=time.time()+300; _OTP["tries"]=0
    return code
def chk_otp(c):
    if _OTP["c"] is None: return False,"No OTP active — request a new one"
    if time.time()>_OTP["x"]: _OTP["c"]=None; return False,"OTP expired"
    _OTP["tries"]+=1
    if c.strip()!=_OTP["c"]:
        if _OTP["tries"]>=5: _OTP["c"]=None; return False,"Too many attempts — request new OTP"
        return False,f"Wrong OTP — {5-_OTP['tries']} attempt(s) left"
    _OTP["c"]=None; return True,"OK"

# ══════════════════════════════════════════════════════════════
#  INVITE / RESET TOKENS
# ══════════════════════════════════════════════════════════════
def make_invite(role="user",hours=24):
    t="".join(random.choices(string.ascii_letters+string.digits,k=40))
    invs=linv(); now=time.time()
    invs={k:v for k,v in invs.items() if v.get("x",0)>now}
    invs[t]={"role":role,"x":now+(hours*3600)}; sinv(invs); return t
def use_invite(t):
    invs=linv()
    if t not in invs: return None,"Invalid invite token"
    if time.time()>invs[t].get("x",0): del invs[t]; sinv(invs); return None,"Invite token expired"
    role=invs[t].get("role","user"); del invs[t]; sinv(invs); return role,"OK"
def make_tok(user):
    t="".join(random.choices(string.ascii_letters+string.digits,k=32))
    tk2=ltok(); now=time.time()
    tk2={k:v for k,v in tk2.items() if v.get("x",0)>now}
    tk2[t]={"u":user,"x":now+600}; stok(tk2); return t
def use_tok(t):
    tk2=ltok()
    if t not in tk2: return None,"Invalid token"
    if time.time()>tk2[t]["x"]: del tk2[t]; stok(tk2); return None,"Expired"
    u=tk2[t]["u"]; del tk2[t]; stok(tk2); return u,"OK"

# ══════════════════════════════════════════════════════════════
#  LOCKOUT
# ══════════════════════════════════════════════════════════════
def bad(u):
    cur=load()
    if u not in cur: return
    cur[u]["ba"]=cur[u].get("ba",0)+1
    if cur[u]["ba"]>=LOCK_MAX: cur[u]["lu"]=time.time()+LOCK_WAIT; cur[u]["ba"]=0; log(f"LOCKED: {u}",u)
    save(cur); DB._reload()
def clr(u):
    cur=load()
    if u in cur: cur[u]["ba"]=0; cur[u]["lu"]=0; save(cur); DB._reload()
def locked(u): d=load(); return u in d and time.time()<d[u].get("lu",0)
def lsec(u): d=load(); return max(0,int(d.get(u,{}).get("lu",0)-time.time()))

