#  USB
# ══════════════════════════════════════════════════════════════
def usb_get():
    try:
        import winreg
        k=winreg.OpenKey(winreg.HKEY_LOCAL_MACHINE,r"SYSTEM\CurrentControlSet\Services\USBSTOR")
        v,_=winreg.QueryValueEx(k,"Start"); winreg.CloseKey(k)
        return "ENABLED" if v==3 else "DISABLED"
    except: return "UNKNOWN"
def usb_set(en,who="SYS"):
    subprocess.run(f'reg add HKLM\\SYSTEM\\CurrentControlSet\\Services\\USBSTOR /v Start /t REG_DWORD /d {"3" if en else "4"} /f',shell=True,capture_output=True)
    log(f"USB {'ENABLED' if en else 'DISABLED'}",who)
def is_admin():
    try: return bool(ctypes.windll.shell32.IsUserAnAdmin())
    except: return False
def devinfo():
    try: comp=socket.gethostname()
    except: comp="N/A"
    try: osv=f"{platform.system()} {platform.release()}"
    except: osv="N/A"
    priv="YES — App has Administrator privileges" if is_admin() else "NO  — Run as Administrator for USB control"
    return {"Computer":comp,"OS":osv,"Admin Privilege":priv,"USB Status":usb_get()}

# ══════════════════════════════════════════════════════════════
#  USB MONITOR
# ══════════════════════════════════════════════════════════════
class USBMon:
    def __init__(self,cb):
        self._cb=cb; self._prev=self._get(); self._on=True
        threading.Thread(target=self._run,daemon=True).start()
    def _get(self):
        try:
            r=subprocess.run("wmic logicaldisk get DeviceID,DriveType",shell=True,capture_output=True,text=True)
            return {p[0] for l in r.stdout.splitlines() for p in [l.split()] if len(p)==2 and p[1]=="2"}
        except: return set()
    def _run(self):
        while self._on:
            c=self._get()
            for d in c-self._prev: self._cb(f"USB INSERTED: {d}")
            for d in self._prev-c: self._cb(f"USB REMOVED:  {d}")
            self._prev=c; time.sleep(2)
    def stop(self): self._on=False

