    sb=tk.Canvas(card,bg=BG3,height=6,highlightthickness=0); sb.pack(fill="x",pady=(3,1))
    sl=tk.Label(card,text="",fg=TXD,bg=BG2,font=("Courier New",8)); sl.pack(anchor="w")
