def usb_panel(parent,username,win_ref,logfn=None):
    stat_var=tk.StringVar(value=usb_get())
    def col(): v=stat_var.get(); return GRN if v=="ENABLED" else RED if v=="DISABLED" else YLW
    tk.Frame(parent,bg=CYN,height=4).pack(fill="x")
    tk.Label(parent,text="USB PORT CONTROL",fg=CYN,bg=BG2,font=("Courier New",22,"bold"),anchor="center").pack(fill="x",ipady=18)
    tk.Frame(parent,bg=BRD,height=1).pack(fill="x")
    stat_lbl=tk.Label(parent,textvariable=stat_var,fg=col(),bg=BG3,font=("Courier New",52,"bold"),anchor="center",pady=28)
    stat_lbl.pack(fill="x",padx=80,pady=24)
    def update(v): stat_var.set(v); stat_lbl.config(fg=col())
    tk.Frame(parent,bg=BRD,height=1).pack(fill="x",padx=80)
    tk.Label(parent,text="SELECT ACTION BELOW",fg=TXD,bg=BG2,font=("Courier New",13)).pack(pady=(22,16))
    brow=tk.Frame(parent,bg=BG2); brow.pack(pady=(0,28))
    def do(enable):
        c=GRN if enable else RED; act="ENABLE USB PORTS" if enable else "DISABLE USB PORTS"
        dlg=tk.Toplevel(win_ref); dlg.title("Confirm"); dlg.configure(bg=BG2)
        dlg.geometry("500x340"); dlg.grab_set(); dlg.resizable(False,False); dlg.lift(); dlg.focus_force()
        tk.Frame(dlg,bg=c,height=4).pack(fill="x")
        tk.Label(dlg,text="CONFIRM ACTION",fg=c,bg=BG2,font=("Courier New",16,"bold")).pack(pady=(22,4))
        tk.Label(dlg,text=act,fg=TXT,bg=BG2,font=("Courier New",14,"bold")).pack()
        tk.Frame(dlg,bg=BRD,height=1).pack(fill="x",padx=40,pady=16)
        tk.Label(dlg,text="Enter your login password to confirm:",fg=TXD,bg=BG2,font=("Courier New",10)).pack(pady=(0,8))
        pf=tk.Frame(dlg,bg=BG3); pf.pack(padx=60,fill="x")
        tk.Frame(pf,bg=CDM,width=4).pack(side="left",fill="y")
        pe=tk.Entry(pf,show="*",bg=BG3,fg=TXT,insertbackground=CYN,font=("Courier New",13),relief="flat",bd=0)
        pe.pack(side="left",fill="x",expand=True,padx=8,pady=10); pe.focus_set()
        el=tk.Label(dlg,text="",fg=RED,bg=BG2,font=("Courier New",9)); el.pack(pady=4)
        def go():
            cur=load()
            if hpw(pe.get())!=cur.get(username,{}).get("password",""):
                el.config(text="  Incorrect password"); return
            usb_set(enable,username); ns="ENABLED" if enable else "DISABLED"; update(ns)
            if logfn: logfn(f"USB {ns} by {username}")
            messagebox.showinfo("Done",f"USB ports {ns}!\nRestart may be needed.",parent=dlg); dlg.destroy()
        dlg.bind("<Return>",lambda e:go())
        tk.Button(dlg,text=f"  CONFIRM — {act}  ",bg=c,fg="black" if enable else "white",
                  font=("Courier New",13,"bold"),relief="flat",cursor="hand2",pady=14,command=go).pack(fill="x",padx=40,pady=(6,4))
        tk.Button(dlg,text="  CANCEL  ",bg=BG3,fg=RED,font=("Courier New",11,"bold"),relief="flat",cursor="hand2",pady=10,command=dlg.destroy).pack(fill="x",padx=40)
    tk.Button(brow,text="  DISABLE USB  ",bg=RED,fg="white",font=("Courier New",20,"bold"),relief="flat",cursor="hand2",padx=40,pady=28,activebackground="#cc001a",command=lambda:do(False)).pack(side="left",padx=20)
    tk.Button(brow,text="  ENABLE USB  ",bg=GRN,fg="black",font=("Courier New",20,"bold"),relief="flat",cursor="hand2",padx=40,pady=28,activebackground="#00cc66",command=lambda:do(True)).pack(side="left",padx=20)
    tk.Frame(parent,bg=BRD,height=1).pack(fill="x",padx=80)
    note="  ✓  Running as Administrator — USB changes apply immediately." if is_admin() else "  ⚠  NOT running as Administrator. Right-click → Run as administrator."
    ncol=GRN if is_admin() else YLW
    tk.Label(parent,text=note,fg=ncol,bg=BG2,font=("Courier New",10),justify="left").pack(pady=14)
    tk.Frame(parent,bg=CYN,height=4).pack(fill="x")

# ══════════════════════════════════════════════════════════════
#  ADMIN REGISTRATION
# ══════════════════════════════════════════════════════════════
def reg_screen(root_ref):
    win=tk.Toplevel(root_ref); win.title("Admin Registration")
    win.configure(bg=BG); win.state("zoomed"); win.resizable(True,True)
    topbar(win,"  ADMIN REGISTRATION","Admin Authorisation Required"); botbar(win)
    card=tk.Frame(win,bg=BG2,padx=60,pady=50); card.place(relx=0.5,rely=0.5,anchor="center",width=600)
    DB._reload(); disk=load()
    existing=[k for k,v in disk.items() if v.get("role") in ("admin","root_admin")]
    def s0():
        for w in card.winfo_children(): w.destroy()
        tk.Frame(card,bg=YLW,height=3).pack(fill="x")
        tk.Label(card,text="ADMIN AUTHORISATION REQUIRED",fg=YLW,bg=BG2,font=("Courier New",15,"bold")).pack(pady=(18,4))
        tk.Label(card,text="An existing admin must approve creation of a new admin account.",fg=TXD,bg=BG2,font=("Courier New",9)).pack()
        tk.Frame(card,bg=BRD,height=1).pack(fill="x",pady=12)
        tk.Label(card,text="EXISTING ADMIN USERNAME",fg=TXD,bg=BG2,font=("Courier New",9)).pack(anchor="w")
        ae=mkentry(card); ae.focus_set()
        tk.Label(card,text="EXISTING ADMIN PASSWORD",fg=TXD,bg=BG2,font=("Courier New",9)).pack(anchor="w",pady=(10,0))
        ape=mkentry(card,show="*"); el=errlbl(card)
        def approve():
            cur=load(); au=ae.get().strip(); ap=hpw(ape.get())
            if au not in cur or cur[au].get("role") not in ("admin","root_admin"): el.config(text="  Admin not found"); return
            if locked(au): el.config(text=f"  Locked — wait {lsec(au)}s"); return
            if cur[au]["password"]!=ap: bad(au); el.config(text="  Wrong password"); return
            clr(au); log(f"Admin '{au}' approved new admin reg",au); s1()
        mkbtn(card,"  APPROVE & PROCEED  ",approve,YLW,"black",13,14).pack(fill="x",pady=8)
        mkbtn(card,"  CANCEL  ",win.destroy,BG3,RED,11,10).pack(fill="x")
        tk.Frame(card,bg=YLW,height=3).pack(fill="x",pady=(20,0))
    def s1():
        for w in card.winfo_children(): w.destroy()
        tk.Frame(card,bg=CYN,height=3).pack(fill="x")
        tk.Label(card,text="STEP 1 OF 3 — EMAIL",fg=CYN,bg=BG2,font=("Courier New",15,"bold")).pack(pady=(18,4))
        tk.Label(card,text="Enter admin email. An OTP will appear to verify it.",fg=TXD,bg=BG2,font=("Courier New",9)).pack()
        tk.Frame(card,bg=BRD,height=1).pack(fill="x",pady=12)
        tk.Label(card,text="ADMIN EMAIL",fg=TXD,bg=BG2,font=("Courier New",9)).pack(anchor="w")
        ee=mkentry(card); ee.focus_set(); el=errlbl(card)
        def send():
            em=ee.get().strip()
            if not re.match(r"[^@]+@[^@]+\.[^@]+",em): el.config(text="  Invalid email"); return
            code=make_otp(); otp_popup(em,code); log(f"Admin reg OTP for {em}"); s2(em)
        mkbtn(card,"  SEND OTP  ",send,CYN,"black",13,14).pack(fill="x",pady=8)
        mkbtn(card,"  CANCEL  ",win.destroy,BG3,RED,11,10).pack(fill="x")
        tk.Frame(card,bg=CYN,height=3).pack(fill="x",pady=(24,0))
    def s2(email):
        for w in card.winfo_children(): w.destroy()
        tk.Frame(card,bg=CYN,height=3).pack(fill="x")
        tk.Label(card,text="STEP 2 OF 3 — VERIFY OTP",fg=CYN,bg=BG2,font=("Courier New",15,"bold")).pack(pady=(18,4))
        tk.Label(card,text=f"Enter OTP shown for {email}",fg=TXD,bg=BG2,font=("Courier New",9)).pack()
        tk.Frame(card,bg=BRD,height=1).pack(fill="x",pady=12)
        tk.Label(card,text="ONE-TIME PASSWORD",fg=TXD,bg=BG2,font=("Courier New",9)).pack(anchor="w")
        oe=mkentry(card); oe.focus_set(); el=errlbl(card)
        def verify():
            ok,msg=chk_otp(oe.get())
            if not ok: el.config(text=f"  {msg}"); return
            s3(email)
        def resend(): code=make_otp(); otp_popup(email,code)
        win.bind("<Return>",lambda e:verify())
        mkbtn(card,"  VERIFY OTP  ",verify,CYN,"black",13,14).pack(fill="x",pady=4)
        mkbtn(card,"  RESEND OTP  ",resend,YLW,"black",11,10).pack(fill="x",pady=4)
        tk.Frame(card,bg=CYN,height=3).pack(fill="x",pady=(24,0))
    def s3(email):
        for w in card.winfo_children(): w.destroy()
        tk.Frame(card,bg=GRN,height=3).pack(fill="x")
        tk.Label(card,text="STEP 3 OF 3 — SET PASSWORD",fg=GRN,bg=BG2,font=("Courier New",15,"bold")).pack(pady=(18,4))
        tk.Frame(card,bg=BRD,height=1).pack(fill="x",pady=12)
        tk.Label(card,text="USERNAME",fg=TXD,bg=BG2,font=("Courier New",9)).pack(anchor="w")
        ue=mkentry(card); ue.focus_set()
        tk.Label(card,text="PASSWORD",fg=TXD,bg=BG2,font=("Courier New",9)).pack(anchor="w",pady=(8,0))
        pe=mkentry(card,show="*"); pw_bar(card,pe)
        tk.Label(card,text="CONFIRM PASSWORD",fg=TXD,bg=BG2,font=("Courier New",9)).pack(anchor="w",pady=(8,0))
        pe2=mkentry(card,show="*"); el=errlbl(card)
        def reg():
            u=ue.get().strip(); pw=pe.get(); pw2=pe2.get()
            if not u: el.config(text="  Username required"); return
            cur=load()
            if u in cur: el.config(text="  Username taken"); return
            errs=pw_ok(pw)
            if errs: el.config(text=f"  {errs[0]}"); return
            if pw!=pw2: el.config(text="  Passwords do not match"); return
            admins=[k for k,v in cur.items() if v.get("role") in ("admin","root_admin")]
            role="root_admin" if not admins else "admin"
            cur[u]={"password":hpw(pw),"role":role,"email":email,"ba":0,"lu":0}
            save(cur); DB._reload()
            badge="ROOT ADMIN" if role=="root_admin" else "ADMIN"
            log(f"{badge} created: {u}",u)
            messagebox.showinfo("Created",f"{badge} account '{u}' created!\nYou can now login.",parent=win)
            win.destroy()
        mkbtn(card,"  CREATE ADMIN ACCOUNT  ",reg,GRN,"black",13,14).pack(fill="x",pady=8)
        tk.Frame(card,bg=GRN,height=3).pack(fill="x",pady=(16,0))
    if existing: s0()
    else:
        for w in card.winfo_children(): w.destroy()
        tk.Frame(card,bg=CYN,height=3).pack(fill="x")
        tk.Label(card,text="ROOT ADMIN SETUP",fg=CYN,bg=BG2,font=("Courier New",15,"bold")).pack(pady=(18,4))
        tk.Label(card,text="No admin exists. You are creating the ROOT admin account.",fg=TXD,bg=BG2,font=("Courier New",9)).pack()
        tk.Label(card,text="Root admin has full control including deleting other admins.",fg=YLW,bg=BG2,font=("Courier New",9,"bold")).pack(pady=(2,0))
        tk.Frame(card,bg=BRD,height=1).pack(fill="x",pady=12)
        mkbtn(card,"  PROCEED TO REGISTRATION  ",s1,CYN,"black",13,14).pack(fill="x",pady=8)
        mkbtn(card,"  CANCEL  ",win.destroy,BG3,RED,11,10).pack(fill="x")
        tk.Frame(card,bg=CYN,height=3).pack(fill="x",pady=(20,0))

# ══════════════════════════════════════════════════════════════
#  ADMIN LOGIN
# ══════════════════════════════════════════════════════════════
def login_screen(root_ref):
    win=tk.Toplevel(root_ref); win.title("Admin Login")
    win.configure(bg=BG); win.state("zoomed"); win.resizable(True,True)
    topbar(win,"  ADMIN LOGIN"); botbar(win)
    card=tk.Frame(win,bg=BG2,padx=60,pady=50); card.place(relx=0.5,rely=0.5,anchor="center",width=600)
    def creds():
        DB._reload()
        for w in card.winfo_children(): w.destroy()
        tk.Frame(card,bg=CYN,height=3).pack(fill="x")
        tk.Label(card,text="ADMIN CREDENTIALS",fg=CYN,bg=BG2,font=("Courier New",15,"bold")).pack(pady=(18,4))
        tk.Frame(card,bg=BRD,height=1).pack(fill="x",pady=12)
        tk.Label(card,text="USERNAME",fg=TXD,bg=BG2,font=("Courier New",9)).pack(anchor="w")
        ue=mkentry(card); ue.focus_set()
        tk.Label(card,text="PASSWORD",fg=TXD,bg=BG2,font=("Courier New",9)).pack(anchor="w",pady=(10,0))
        pe=mkentry(card,show="*"); el=errlbl(card)
        def go():
            cur=load(); u=ue.get().strip(); p=hpw(pe.get())
            if u not in cur or cur[u].get("role") not in ("admin","root_admin"): el.config(text="  Admin account not found"); return
            if locked(u): el.config(text=f"  Locked — wait {lsec(u)}s"); return
            if cur[u]["password"]!=p:
                bad(u); log(f"Bad admin login: {u}")
                el.config(text=f"  Wrong password — {LOCK_MAX-cur.get(u,{}).get('ba',0)} left"); return
            clr(u); code=make_otp(); otp_popup(cur[u].get("email","unknown@email.com"),code); otp_step(u)
        def forgot():
            cur=load(); u=ue.get().strip()
            if u not in cur: el.config(text="  Enter username first"); return
            em=cur[u].get("email","")
            if not em: el.config(text="  No email on record"); return
            tok=make_tok(u); reset_tok_popup(em,tok); log(f"Admin password reset requested: {u}")
        win.bind("<Return>",lambda e:go())
        mkbtn(card,"  LOGIN  ",go,CYN,"black",14,16).pack(fill="x",pady=8)
        mkbtn(card,"  FORGOT PASSWORD  ",forgot,ORG,"black",11,10).pack(fill="x",pady=4)
        mkbtn(card,"  REGISTER NEW ADMIN  ",lambda:reg_screen(root_ref),YLW,"black",11,10).pack(fill="x",pady=4)
        mkbtn(card,"  BACK  ",win.destroy,BG3,RED,11,10).pack(fill="x",pady=4)
        tk.Frame(card,bg=CYN,height=3).pack(fill="x",pady=(20,0))
    def otp_step(username):
        for w in card.winfo_children(): w.destroy()
        cur=load(); email=cur.get(username,{}).get("email","")
        tk.Frame(card,bg=CYN,height=3).pack(fill="x")
        tk.Label(card,text="VERIFY OTP",fg=CYN,bg=BG2,font=("Courier New",15,"bold")).pack(pady=(18,4))
        tk.Label(card,text=f"Enter OTP from the popup ({email})",fg=TXD,bg=BG2,font=("Courier New",9)).pack()
        tk.Frame(card,bg=BRD,height=1).pack(fill="x",pady=12)
        tk.Label(card,text="ONE-TIME PASSWORD",fg=TXD,bg=BG2,font=("Courier New",9)).pack(anchor="w")
        oe=mkentry(card); oe.focus_set(); el=errlbl(card)
        def verify():
            ok,msg=chk_otp(oe.get())
            if not ok: el.config(text=f"  {msg}"); return
            log(f"Admin login OK: {username}",username); win.destroy(); admin_dash(username,root_ref)
        win.bind("<Return>",lambda e:verify())
        mkbtn(card,"  VERIFY  ",verify,CYN,"black",14,16).pack(fill="x",pady=8)
        tk.Frame(card,bg=CYN,height=3).pack(fill="x",pady=(20,0))
    creds()

