#  ADMIN RESET PASSWORD
# ══════════════════════════════════════════════════════════════
def reset_screen(root_ref):
    win=tk.Toplevel(root_ref); win.title("Reset Password")
    win.configure(bg=BG); win.state("zoomed"); win.resizable(True,True)
    topbar(win,"  RESET PASSWORD","Paste token from popup, set new password"); botbar(win)
    card=tk.Frame(win,bg=BG2,padx=60,pady=50); card.place(relx=0.5,rely=0.5,anchor="center",width=600)
    tk.Frame(card,bg=ORG,height=3).pack(fill="x")
    tk.Label(card,text="RESET PASSWORD",fg=ORG,bg=BG2,font=("Courier New",15,"bold")).pack(pady=(18,4))
    tk.Label(card,text="Paste the reset token shown in the popup, then set a new password.",fg=TXD,bg=BG2,font=("Courier New",9)).pack()
    tk.Frame(card,bg=BRD,height=1).pack(fill="x",pady=12)
    tk.Label(card,text="RESET TOKEN",fg=TXD,bg=BG2,font=("Courier New",9)).pack(anchor="w")
    te=mkentry(card); te.focus_set()
    tk.Label(card,text="NEW PASSWORD",fg=TXD,bg=BG2,font=("Courier New",9)).pack(anchor="w",pady=(10,0))
    pe=mkentry(card,show="*"); pw_bar(card,pe)
    tk.Label(card,text="CONFIRM PASSWORD",fg=TXD,bg=BG2,font=("Courier New",9)).pack(anchor="w",pady=(10,0))
    pe2=mkentry(card,show="*"); el=errlbl(card); ol=oklbl(card)
    def do():
        u,msg=use_tok(te.get().strip())
        if not u: el.config(text=f"  {msg}"); ol.config(text=""); return
        pw=pe.get(); errs=pw_ok(pw)
        if errs: el.config(text=f"  {errs[0]}"); return
        if pw!=pe2.get(): el.config(text="  Passwords do not match"); return
        cur=load(); cur[u]["password"]=hpw(pw); save(cur); DB._reload()
        log(f"Password reset: {u}",u); el.config(text="")
        ol.config(text=f"  Password reset for '{u}'. You can now login.")
        messagebox.showinfo("Done",f"Password reset for '{u}'!\nYou can now login.",parent=win)
    mkbtn(card,"  RESET PASSWORD  ",do,ORG,"black",13,14).pack(fill="x",pady=8)
    mkbtn(card,"  BACK  ",win.destroy,BG3,RED,11,10).pack(fill="x")
    tk.Frame(card,bg=ORG,height=3).pack(fill="x",pady=(20,0))

# ══════════════════════════════════════════════════════════════
#  USER SELF-REGISTRATION
# ══════════════════════════════════════════════════════════════
def user_register_screen(root_ref):
    win=tk.Toplevel(root_ref); win.title("Register New Account")
    win.configure(bg=BG); win.state("zoomed"); win.resizable(True,True)
    topbar(win,"  REGISTER NEW ACCOUNT","Get invite token + OTP via email"); botbar(win)
    cv=tk.Canvas(win,bg=BG,highlightthickness=0); vsb=tk.Scrollbar(win,orient="vertical",command=cv.yview)
    cv.configure(yscrollcommand=vsb.set); vsb.pack(side="right",fill="y"); cv.pack(fill="both",expand=True)
    inner=tk.Frame(cv,bg=BG); cv.create_window((0,0),window=inner,anchor="nw")
    inner.bind("<Configure>",lambda e:cv.configure(scrollregion=cv.bbox("all")))
    card=tk.Frame(inner,bg=BG2,padx=60,pady=50); card.pack(fill="x",padx=80,pady=30)
    def step1():
        for w in card.winfo_children(): w.destroy()
        tk.Frame(card,bg=CYN,height=3).pack(fill="x")
        tk.Label(card,text="STEP 1 OF 3 — ENTER YOUR EMAIL",fg=CYN,bg=BG2,font=("Courier New",15,"bold")).pack(pady=(18,4))
        tk.Label(card,text="Enter your email. A popup shows your INVITE TOKEN and OTP.",fg=TXD,bg=BG2,font=("Courier New",9),justify="center").pack(pady=(0,4))
        tk.Frame(card,bg=BRD,height=1).pack(fill="x",pady=12)
        tk.Label(card,text="YOUR EMAIL ADDRESS",fg=TXD,bg=BG2,font=("Courier New",9)).pack(anchor="w")
        ee=mkentry(card); ee.focus_set(); el=errlbl(card)
        def send():
            em=ee.get().strip()
            if not re.match(r"[^@]+@[^@]+\.[^@]+",em): el.config(text="  Invalid email"); return
            cur=load()
            if any(v.get("email","").lower()==em.lower() for v in cur.values()): el.config(text="  Already registered"); return
            inv=make_invite(role="user",hours=24); otp=make_otp()
            invite_otp_popup(em,inv,otp); log(f"Self-reg for {em}"); step2(em,inv)
        win.bind("<Return>",lambda e:send())
        mkbtn(card,"  GET INVITE TOKEN & OTP  ",send,CYN,"black",13,14).pack(fill="x",pady=8)
        mkbtn(card,"  BACK  ",win.destroy,BG3,RED,11,10).pack(fill="x")
        tk.Frame(card,bg=CYN,height=3).pack(fill="x",pady=(20,0))
    def step2(email,inv):
        for w in card.winfo_children(): w.destroy()
        tk.Frame(card,bg=CYN,height=3).pack(fill="x")
        tk.Label(card,text="STEP 2 OF 3 — VERIFY OTP",fg=CYN,bg=BG2,font=("Courier New",15,"bold")).pack(pady=(18,4))
        tk.Label(card,text="Enter the OTP from the popup window.",fg=TXD,bg=BG2,font=("Courier New",9)).pack()
        tk.Frame(card,bg=BRD,height=1).pack(fill="x",pady=12)
        tk.Label(card,text="ENTER OTP FROM POPUP",fg=TXD,bg=BG2,font=("Courier New",9)).pack(anchor="w")
        oe=mkentry(card); oe.focus_set(); el=errlbl(card)
        def verify():
            ok,msg=chk_otp(oe.get())
            if not ok: el.config(text=f"  {msg}"); return
            step3(email,inv)
        def resend():
            ni=make_invite(role="user",hours=24); no=make_otp()
            invite_otp_popup(email,ni,no); step2(email,ni)
        win.bind("<Return>",lambda e:verify())
        mkbtn(card,"  VERIFY OTP  ",verify,CYN,"black",13,14).pack(fill="x",pady=4)
        mkbtn(card,"  RESEND  ",resend,YLW,"black",11,10).pack(fill="x",pady=4)
        mkbtn(card,"  BACK  ",step1,BG3,TXD,11,10).pack(fill="x",pady=4)
        tk.Frame(card,bg=CYN,height=3).pack(fill="x",pady=(20,0))
    def step3(email,inv):
        for w in card.winfo_children(): w.destroy()
        tk.Frame(card,bg=GRN,height=3).pack(fill="x")
        tk.Label(card,text="STEP 3 OF 3 — PASTE TOKEN & SET PASSWORD",fg=GRN,bg=BG2,font=("Courier New",15,"bold")).pack(pady=(18,4))
        tk.Label(card,text="Paste your Invite Token from the popup.\nThen choose your username and password.",fg=TXD,bg=BG2,font=("Courier New",9),justify="center").pack(pady=(0,4))
        tk.Frame(card,bg=BRD,height=1).pack(fill="x",pady=12)
        tk.Label(card,text="INVITE TOKEN (from popup — already copied)",fg=YLW,bg=BG2,font=("Courier New",9,"bold")).pack(anchor="w")
        tf=tk.Frame(card,bg=BG3,pady=1); tf.pack(fill="x",pady=2)
        tk.Frame(tf,bg=YLW,width=4).pack(side="left",fill="y")
        te=tk.Entry(tf,bg=BG3,fg=YLW,insertbackground=YLW,font=("Courier New",10),relief="flat",bd=0)
        te.pack(side="left",fill="x",expand=True,padx=8,pady=9); te.focus_set()
        try:
            clip=win.clipboard_get()
            if len(clip)==40: te.insert(0,clip)
        except: pass
        tk.Label(card,text="USERNAME",fg=TXD,bg=BG2,font=("Courier New",9)).pack(anchor="w",pady=(10,0)); ue=mkentry(card)
        tk.Label(card,text="PASSWORD",fg=TXD,bg=BG2,font=("Courier New",9)).pack(anchor="w",pady=(10,0))
        pe=mkentry(card,show="*"); pw_bar(card,pe)
        tk.Label(card,text="CONFIRM PASSWORD",fg=TXD,bg=BG2,font=("Courier New",9)).pack(anchor="w",pady=(10,0))
        pe2=mkentry(card,show="*"); el=errlbl(card)
        def create():
            tok=te.get().strip(); u=ue.get().strip(); pw=pe.get(); pw2=pe2.get()
            if not tok: el.config(text="  Invite token required"); return
            if not u: el.config(text="  Username required"); return
            role,msg=use_invite(tok)
            if not role: el.config(text=f"  Token error: {msg}"); return
            cur=load()
            if u in cur: el.config(text="  Username already taken"); return
            if any(v.get("email","").lower()==email.lower() for v in cur.values()): el.config(text="  Email already registered"); return
            errs=pw_ok(pw)
            if errs: el.config(text=f"  {errs[0]}"); return
            if pw!=pw2: el.config(text="  Passwords do not match"); return
            cur[u]={"password":hpw(pw),"role":role,"email":email,"ba":0,"lu":0}
            save(cur); DB._reload(); log(f"Self-registered: {u} [{role}] <{email}>",u)
            messagebox.showinfo("Account Created",f"Account created!\n\nUsername: {u}\nRole: {role.upper()}\nEmail: {email}\n\nYou can now login.",parent=win)
            win.destroy()
        win.bind("<Return>",lambda e:create())
        mkbtn(card,"  CREATE MY ACCOUNT  ",create,GRN,"black",13,14).pack(fill="x",pady=8)
        mkbtn(card,"  BACK  ",step1,BG3,RED,11,10).pack(fill="x")
        tk.Frame(card,bg=GRN,height=3).pack(fill="x",pady=(16,0))
    step1()

# ══════════════════════════════════════════════════════════════
#  USER FORGOT PASSWORD
# ══════════════════════════════════════════════════════════════
def user_forgot_screen(root_ref):
    win=tk.Toplevel(root_ref); win.title("Forgot Password")
    win.configure(bg=BG); win.state("zoomed"); win.resizable(True,True)
    topbar(win,"  FORGOT PASSWORD","Reset via email OTP"); botbar(win)
    card=tk.Frame(win,bg=BG2,padx=60,pady=50); card.place(relx=0.5,rely=0.5,anchor="center",width=620)
    def step1():
        for w in card.winfo_children(): w.destroy()
        tk.Frame(card,bg=ORG,height=3).pack(fill="x")
        tk.Label(card,text="STEP 1 OF 2 — VERIFY YOUR EMAIL",fg=ORG,bg=BG2,font=("Courier New",15,"bold")).pack(pady=(18,4))
        tk.Label(card,text="Enter your username and registered email.",fg=TXD,bg=BG2,font=("Courier New",9)).pack()
        tk.Frame(card,bg=BRD,height=1).pack(fill="x",pady=12)
        tk.Label(card,text="USERNAME",fg=TXD,bg=BG2,font=("Courier New",9)).pack(anchor="w")
        ue=mkentry(card); ue.focus_set()
        tk.Label(card,text="REGISTERED EMAIL ADDRESS",fg=TXD,bg=BG2,font=("Courier New",9)).pack(anchor="w",pady=(10,0))
        ee=mkentry(card); el=errlbl(card)
        def send():
            u=ue.get().strip(); em=ee.get().strip(); cur=load()
            if u not in cur: el.config(text="  Username not found"); return
            if cur[u].get("role") in ("admin","root_admin"): el.config(text="  Use Admin Forgot Password"); return
            if not re.match(r"[^@]+@[^@]+\.[^@]+",em): el.config(text="  Invalid email"); return
            stored=cur[u].get("email","").lower()
            if stored and stored!=em.lower(): el.config(text="  Email does not match records"); return
            code=make_otp(); otp_popup(em,code); log(f"User PW reset OTP for {u}",u); step2(u,em)
        win.bind("<Return>",lambda e:send())
        mkbtn(card,"  SEND OTP  ",send,ORG,"black",13,14).pack(fill="x",pady=8)
        mkbtn(card,"  BACK  ",win.destroy,BG3,RED,11,10).pack(fill="x")
        tk.Frame(card,bg=ORG,height=3).pack(fill="x",pady=(20,0))
    def step2(username,email):
        for w in card.winfo_children(): w.destroy()
        tk.Frame(card,bg=ORG,height=3).pack(fill="x")
        tk.Label(card,text="STEP 2 OF 2 — VERIFY OTP & SET PASSWORD",fg=ORG,bg=BG2,font=("Courier New",15,"bold")).pack(pady=(18,4))
        tk.Label(card,text=f"Account: {username}",fg=TXD,bg=BG2,font=("Courier New",9)).pack()
        tk.Frame(card,bg=BRD,height=1).pack(fill="x",pady=12)
        tk.Label(card,text="OTP CODE",fg=TXD,bg=BG2,font=("Courier New",9)).pack(anchor="w")
        oe=mkentry(card); oe.focus_set()
        tk.Frame(card,bg=BRD,height=1).pack(fill="x",pady=8)
        tk.Label(card,text="NEW PASSWORD",fg=TXD,bg=BG2,font=("Courier New",9)).pack(anchor="w")
        pe=mkentry(card,show="*"); pw_bar(card,pe)
        tk.Label(card,text="CONFIRM NEW PASSWORD",fg=TXD,bg=BG2,font=("Courier New",9)).pack(anchor="w",pady=(10,0))
        pe2=mkentry(card,show="*"); el=errlbl(card)
        def reset():
            ok,msg=chk_otp(oe.get())
            if not ok: el.config(text=f"  {msg}"); return
            pw=pe.get(); errs=pw_ok(pw)
            if errs: el.config(text=f"  {errs[0]}"); return
            if pw!=pe2.get(): el.config(text="  Passwords do not match"); return
            cur=load(); cur[username]["password"]=hpw(pw)
            if not cur[username].get("email"): cur[username]["email"]=email
            save(cur); DB._reload(); log(f"User PW reset: {username}",username)
            messagebox.showinfo("Done",f"Password reset for '{username}'!\nYou can now login.",parent=win); win.destroy()
        def resend(): code=make_otp(); otp_popup(email,code)
        win.bind("<Return>",lambda e:reset())
        mkbtn(card,"  VERIFY OTP & RESET PASSWORD  ",reset,ORG,"black",13,14).pack(fill="x",pady=8)
        mkbtn(card,"  RESEND OTP  ",resend,YLW,"black",11,10).pack(fill="x",pady=4)
        mkbtn(card,"  BACK  ",step1,BG3,TXD,11,10).pack(fill="x",pady=4)
        tk.Frame(card,bg=ORG,height=3).pack(fill="x",pady=(20,0))
    step1()

