#  USER LOGIN
# ══════════════════════════════════════════════════════════════
def user_login(root_ref):
    win=tk.Toplevel(root_ref); win.title("User Login")
    win.configure(bg=BG); win.state("zoomed"); win.resizable(True,True)
    topbar(win,"  USER LOGIN"); botbar(win)
    card=tk.Frame(win,bg=BG2,padx=60,pady=50); card.place(relx=0.5,rely=0.5,anchor="center",width=580)
    tk.Frame(card,bg=GRN,height=3).pack(fill="x")
    tk.Label(card,text="USER LOGIN",fg=GRN,bg=BG2,font=("Courier New",15,"bold")).pack(pady=(18,4))
    tk.Frame(card,bg=BRD,height=1).pack(fill="x",pady=12)
    tk.Label(card,text="USERNAME",fg=TXD,bg=BG2,font=("Courier New",9)).pack(anchor="w")
    ue=mkentry(card); ue.focus_set()
    tk.Label(card,text="PASSWORD",fg=TXD,bg=BG2,font=("Courier New",9)).pack(anchor="w",pady=(10,0))
    pe=mkentry(card,show="*"); el=errlbl(card)
    def go():
        u=ue.get().strip(); p=hpw(pe.get()); cur=load()
        if u not in cur: el.config(text="  User not found"); return
        if cur[u].get("role") in ("admin","root_admin"): el.config(text="  Use Admin Login for admin accounts"); return
        if locked(u): el.config(text=f"  Locked — wait {lsec(u)}s"); return
        if cur[u]["password"]!=p:
            bad(u); log(f"Bad user login: {u}")
            el.config(text=f"  Wrong password — {LOCK_MAX-cur.get(u,{}).get('ba',0)} left"); return
        clr(u); log(f"User login: {u}",u); win.destroy(); user_dash(u,root_ref)
    win.bind("<Return>",lambda e:go())
    mkbtn(card,"  LOGIN  ",go,GRN,"black",14,16).pack(fill="x",pady=8)
    mkbtn(card,"  FORGOT PASSWORD  ",lambda:user_forgot_screen(root_ref),ORG,"black",11,10).pack(fill="x",pady=4)
    mkbtn(card,"  BACK  ",win.destroy,BG3,RED,11,10).pack(fill="x",pady=4)
    tk.Frame(card,bg=GRN,height=3).pack(fill="x",pady=(20,0))

# ══════════════════════════════════════════════════════════════
#  ADMIN DASHBOARD
# ══════════════════════════════════════════════════════════════
def admin_dash(username,root_ref):
    win=tk.Toplevel(root_ref); win.title("Admin Dashboard")
    win.configure(bg=BG); win.state("zoomed"); win.resizable(True,True)
    _t=[time.time()]
    win.bind("<KeyPress>",   lambda e:_t.__setitem__(0,time.time()))
    win.bind("<ButtonPress>",lambda e:_t.__setitem__(0,time.time()))
    def idle_chk():
        try:
            if not win.winfo_exists(): return
        except: return
        if time.time()-_t[0]>IDLE_TIME:
            log(f"Session timeout: {username}",username)
            try: mon.stop()
            except: pass
            try: win.destroy()
            except: pass
            return
        win.after(10000,idle_chk)
    win.after(10000,idle_chk)
    _lb=[None]
    def logit(msg):
        log(msg,username)
        try:
            lb=_lb[0]
            if lb and lb.winfo_exists():
                lb.config(state="normal"); lb.insert("end",f"  [{time.strftime('%H:%M:%S')}] {msg}\n")
                lb.see("end"); lb.config(state="disabled")
        except: pass
    mon=USBMon(lambda m:win.after(0,lambda:logit(m)))
    cur_role=load().get(username,{}).get("role","admin")
    badge="ROOT ADMIN" if cur_role=="root_admin" else "ADMIN"
    topbar(win,"  ADMIN CONTROL PANEL",f"OPERATOR: {username.upper()}  [{badge}]"); botbar(win)
    tbar=tk.Frame(win,bg=BG3); tbar.pack(fill="x")
    tk.Frame(tbar,bg=BRD,height=1).pack(fill="x",side="bottom")
    area=tk.Frame(win,bg=BG); area.pack(fill="both",expand=True)
    tbtn={}
    def sw(name,fn):
        for n,b in tbtn.items(): b.config(bg=BG3 if n!=name else BG2,fg=TXD if n!=name else CYN)
        for w in area.winfo_children(): w.destroy()
        f=tk.Frame(area,bg=BG); f.pack(fill="both",expand=True); fn(f)
    def tab(name,fn):
        b=tk.Label(tbar,text=f"  {name}  ",bg=BG3,fg=TXD,font=("Courier New",11,"bold"),padx=6,pady=10,cursor="hand2")
        b.pack(side="left"); b.bind("<Button-1>",lambda e:sw(name,fn)); tbtn[name]=b
    def t_usb(f):
        left=tk.Frame(f,bg=BG2); left.pack(side="left",fill="both",expand=True)
        usb_panel(left,username,win,logit)
        right=tk.Frame(f,bg=BG2,width=400); right.pack(side="right",fill="y"); right.pack_propagate(False)
        tk.Frame(right,bg=CYN,height=2).pack(fill="x")
        tk.Label(right,text="  LIVE LOG",fg=CYN,bg=BG2,font=("Courier New",11,"bold")).pack(anchor="w",pady=(10,4),padx=10)
        lb=tk.Text(right,bg=BG3,fg=CDM,font=("Courier New",8),relief="flat",bd=0,state="disabled",wrap="word")
        lb.pack(fill="both",expand=True,padx=8,pady=(0,8)); _lb[0]=lb
        dec_log=_log_dec_all(LOG_FILE)
        if dec_log:
            lb.config(state="normal")
            for l in dec_log.split("\n")[-80:]: lb.insert("end",l+"\n")
            lb.see("end"); lb.config(state="disabled")
        logit(f"Dashboard opened — {username}")
    def t_ov(f):
        tk.Label(f,text="DEVICE INFORMATION",fg=CYN,bg=BG,font=("Courier New",16,"bold")).pack(anchor="w",padx=40,pady=(24,12))
        c=tk.Frame(f,bg=BG2,padx=30,pady=20); c.pack(fill="x",padx=40)
        tk.Frame(c,bg=CYN,height=2).pack(fill="x")
        for k,v in devinfo().items():
            r=tk.Frame(c,bg=BG2); r.pack(fill="x",pady=5)
            tk.Label(r,text=f"  {k}:",fg=TXD,bg=BG2,font=("Courier New",10),width=18,anchor="w").pack(side="left")
            if k=="Admin Privilege": vc=GRN if v.startswith("YES") else YLW
            elif k=="USB Status": vc=GRN if v=="ENABLED" else(RED if v=="DISABLED" else YLW)
            else: vc=TXT
            tk.Label(r,text=v,fg=vc,bg=BG2,font=("Courier New",11,"bold"),wraplength=700,justify="left").pack(side="left")
    def t_users(f):
        is_root=(load().get(username,{}).get("role")=="root_admin")
        tk.Label(f,text="USER MANAGEMENT",fg=CYN,bg=BG,font=("Courier New",16,"bold")).pack(anchor="w",padx=30,pady=(16,10))
        ec=tk.Frame(f,bg=BG2,padx=24,pady=14); ec.pack(fill="x",padx=30,pady=(0,10))
        tk.Frame(ec,bg=GRN,height=2).pack(fill="x")
        tk.Label(ec,text="ENROL NEW USER DIRECTLY",fg=GRN,bg=BG2,font=("Courier New",12,"bold")).pack(pady=(10,8))
        row=tk.Frame(ec,bg=BG2); row.pack(fill="x",pady=4)
        tk.Label(row,text="Username:",fg=TXD,bg=BG2,font=("Courier New",9),width=12,anchor="w").pack(side="left")
        nue=tk.Entry(row,bg=BG3,fg=TXT,font=("Courier New",11),relief="flat"); nue.pack(side="left",padx=(4,16))
        tk.Label(row,text="Role:",fg=TXD,bg=BG2,font=("Courier New",9)).pack(side="left")
        rv=tk.StringVar(value="user"); roles=["user","admin"] if is_root else ["user"]
        tk.OptionMenu(row,rv,*roles).pack(side="left",padx=4)
        row2=tk.Frame(ec,bg=BG2); row2.pack(fill="x",pady=4)
        tk.Label(row2,text="Password:",fg=TXD,bg=BG2,font=("Courier New",9),width=12,anchor="w").pack(side="left")
        npe=tk.Entry(row2,show="*",bg=BG3,fg=TXT,font=("Courier New",11),relief="flat"); npe.pack(side="left",padx=4)
        eel=tk.Label(ec,text="",fg=RED,bg=BG2,font=("Courier New",9)); eel.pack()
        def enrol():
            u=nue.get().strip(); pw=npe.get(); r=rv.get()
            if not u: eel.config(text="  Username required"); return
            cur=load()
            if u in cur: eel.config(text="  User exists"); return
            errs=pw_ok(pw)
            if errs: eel.config(text=f"  {errs[0]}"); return
            cur[u]={"password":hpw(pw),"role":r,"email":"","ba":0,"lu":0}
            save(cur); DB._reload(); logit(f"User enrolled: {u} [{r}]")
            eel.config(fg=GRN,text=f"  User '{u}' [{r}] created")
            nue.delete(0,"end"); npe.delete(0,"end"); refresh_list(lc)
        mkbtn(ec,"  ENROL USER  ",enrol,GRN,"black",11,8).pack(pady=6)
        lc=tk.Frame(f,bg=BG2,padx=16,pady=10); lc.pack(fill="both",expand=True,padx=30)
        def refresh_list(container):
            for w in container.winfo_children():
                if getattr(w,"_r",False): w.destroy()
            disk=load()
            tk.Frame(container,bg=CYN,height=2).pack(fill="x")
            lh=tk.Label(container,text="EXISTING ACCOUNTS",fg=CYN,bg=BG2,font=("Courier New",11,"bold")); lh.pack(pady=(10,2)); lh._r=False
            hdr=tk.Frame(container,bg=BG3); hdr.pack(fill="x",pady=(0,2)); hdr._r=True
            for t,w_ in [("USERNAME",20),("ROLE",10),("EMAIL",22),("STATUS",8),("ACTIONS",18)]:
                tk.Label(hdr,text=t,fg=TXD,bg=BG3,font=("Courier New",8,"bold"),width=w_,anchor="w").pack(side="left",padx=4)
            for un,ud in list(disk.items()):
                if un==username: continue
                urole=ud.get("role","user")
                bm={"root_admin":("[ROOT]",YLW),"admin":("[ADM]",CYN),"user":("[USR]",GRN)}
                bgt,bcol=bm.get(urole,("[USR]",GRN))
                st="LOCKED" if(time.time()<ud.get("lu",0)) else "ACTIVE"; sc=RED if st=="LOCKED" else GRN
                row=tk.Frame(container,bg=BG3,pady=5,padx=8); row.pack(fill="x",pady=2); row._r=True
                tk.Label(row,text=un,fg=TXT,bg=BG3,font=("Courier New",10,"bold"),width=20,anchor="w").pack(side="left",padx=2)
                tk.Label(row,text=bgt,fg=bcol,bg=BG3,font=("Courier New",9,"bold"),width=10,anchor="w").pack(side="left")
                tk.Label(row,text=ud.get("email","—"),fg=TXD,bg=BG3,font=("Courier New",8),width=22,anchor="w").pack(side="left")
                tk.Label(row,text=st,fg=sc,bg=BG3,font=("Courier New",9),width=8,anchor="w").pack(side="left")
                act=tk.Frame(row,bg=BG3); act.pack(side="left")
                def mk_del(n):
                    def _():
                        d=load()
                        if d.get(n,{}).get("role")=="root_admin": messagebox.showerror("Forbidden","Root admin cannot be deleted here.\nUse MY ACCOUNT > DANGER ZONE.",parent=win); return
                        if messagebox.askyesno("Delete",f"Delete '{n}'?",parent=win):
                            del d[n]; save(d); DB._reload(); logit(f"Account deleted: {n}"); refresh_list(container)
                    return _
                def mk_pw(n):
                    def _():
                        if load().get(n,{}).get("role")=="root_admin": messagebox.showerror("Protected","Root admin cannot be modified by others.",parent=win); return
                        d2=tk.Toplevel(win); d2.title(f"Change PW — {n}"); d2.configure(bg=BG2); d2.geometry("420x260"); d2.grab_set()
                        tk.Label(d2,text=f"New password for: {n}",fg=CYN,bg=BG2,font=("Courier New",12,"bold")).pack(pady=14)
                        p1=tk.Entry(d2,show="*",bg=BG3,fg=TXT,font=("Courier New",12),relief="flat"); p1.pack(padx=40,fill="x",pady=4); p1.focus_set()
                        p2=tk.Entry(d2,show="*",bg=BG3,fg=TXT,font=("Courier New",12),relief="flat"); p2.pack(padx=40,fill="x",pady=4)
                        el2=tk.Label(d2,text="",fg=RED,bg=BG2,font=("Courier New",9)); el2.pack()
                        def sv():
                            p=p1.get(); e=pw_ok(p)
                            if e: el2.config(text=f"  {e[0]}"); return
                            if p!=p2.get(): el2.config(text="  Mismatch"); return
                            cur2=load(); cur2[n]["password"]=hpw(p); save(cur2); DB._reload(); logit(f"Password changed: {n}"); d2.destroy()
                        mkbtn(d2,"  SAVE  ",sv,GRN,"black",11,10).pack(pady=10)
                    return _
                if urole!="root_admin": mkbtn(act,"DELETE",mk_del(un),RED,"white",8,5).pack(side="left",padx=2)
                else: tk.Label(act,text="[PROTECTED]",fg=TXD,bg=BG3,font=("Courier New",7)).pack(side="left",padx=4)
                mkbtn(act,"CHG PW",mk_pw(un),YLW,"black",8,5).pack(side="left",padx=2)
        refresh_list(lc)
    def t_acc(f):
        my_role=load().get(username,{}).get("role","admin"); is_root=(my_role=="root_admin")
        _cv=tk.Canvas(f,bg=BG,highlightthickness=0); _sb=tk.Scrollbar(f,orient="vertical",command=_cv.yview)
        _cv.configure(yscrollcommand=_sb.set); _sb.pack(side="right",fill="y"); _cv.pack(fill="both",expand=True)
        outer=tk.Frame(_cv,bg=BG); win_id=_cv.create_window((0,0),window=outer,anchor="nw")
        def _resize(e): _cv.itemconfig(win_id,width=e.width)
        _cv.bind("<Configure>",_resize); outer.bind("<Configure>",lambda e:_cv.configure(scrollregion=_cv.bbox("all")))
        c=tk.Frame(outer,bg=BG2,padx=50,pady=30); c.pack(fill="x",padx=50,pady=(30,20))
        acc=YLW if is_root else CYN
        tk.Frame(c,bg=acc,height=3).pack(fill="x")
        tk.Label(c,text=f"MY ACCOUNT  [{'ROOT ADMIN' if is_root else 'ADMIN'}]",fg=acc,bg=BG2,font=("Courier New",14,"bold")).pack(pady=(16,4))
        if is_root: tk.Label(c,text="You are the ROOT admin — full system privileges.",fg=YLW,bg=BG2,font=("Courier New",9,"bold")).pack(pady=(0,8))
        tk.Frame(c,bg=BRD,height=1).pack(fill="x",pady=8)
        tk.Label(c,text="CHANGE MY PASSWORD",fg=TXD,bg=BG2,font=("Courier New",11,"bold")).pack(anchor="w",pady=(0,6))
        tk.Label(c,text="Current Password",fg=TXD,bg=BG2,font=("Courier New",9)).pack(anchor="w")
        cp=tk.Entry(c,show="*",bg=BG3,fg=TXT,font=("Courier New",12),relief="flat"); cp.pack(fill="x",pady=(4,10)); cp.focus_set()
        tk.Label(c,text="New Password",fg=TXD,bg=BG2,font=("Courier New",9)).pack(anchor="w")
        np_=tk.Entry(c,show="*",bg=BG3,fg=TXT,font=("Courier New",12),relief="flat"); np_.pack(fill="x",pady=(4,6)); pw_bar(c,np_)
        tk.Label(c,text="Confirm New Password",fg=TXD,bg=BG2,font=("Courier New",9)).pack(anchor="w")
        np2=tk.Entry(c,show="*",bg=BG3,fg=TXT,font=("Courier New",12),relief="flat"); np2.pack(fill="x",pady=(4,14))
        al=tk.Label(c,text="",fg=RED,bg=BG2,font=("Courier New",9)); al.pack()
        ol2=tk.Label(c,text="",fg=GRN,bg=BG2,font=("Courier New",9)); ol2.pack()
        def chpw():
            cur=load()
            if hpw(cp.get())!=cur.get(username,{}).get("password",""): al.config(text="  Wrong current password"); ol2.config(text=""); return
            pw=np_.get(); e=pw_ok(pw)
            if e: al.config(text=f"  {e[0]}"); return
            if pw!=np2.get(): al.config(text="  Passwords don't match"); return
            cur[username]["password"]=hpw(pw); save(cur); DB._reload(); logit("Admin changed own password"); al.config(text=""); ol2.config(text="  Password updated!")
        mkbtn(c,"  UPDATE PASSWORD  ",chpw,YLW,"black",13,14).pack(fill="x",pady=8)
        if is_root:
            dc=tk.Frame(outer,bg=BG2,padx=50,pady=24); dc.pack(fill="x",padx=50,pady=(0,30))
            tk.Frame(dc,bg=RED,height=3).pack(fill="x")
            tk.Label(dc,text="DANGER ZONE — DELETE ROOT ACCOUNT",fg=RED,bg=BG2,font=("Courier New",13,"bold")).pack(pady=(16,4))
            tk.Label(dc,text="Permanently deletes your root admin account. Irreversible.",fg=TXD,bg=BG2,font=("Courier New",9),wraplength=460).pack(pady=(0,12))
            tk.Frame(dc,bg=BRD,height=1).pack(fill="x",pady=(0,12))
            tk.Label(dc,text="Enter password to confirm:",fg=TXD,bg=BG2,font=("Courier New",9)).pack(anchor="w")
            dep=tk.Entry(dc,show="*",bg=BG3,fg=TXT,font=("Courier New",12),relief="flat"); dep.pack(fill="x",pady=(4,8))
            del_el=tk.Label(dc,text="",fg=RED,bg=BG2,font=("Courier New",9)); del_el.pack()
            def del_root():
                cur=load()
                if hpw(dep.get())!=cur.get(username,{}).get("password",""): del_el.config(text="  Wrong password"); return
                if not messagebox.askyesno("FINAL WARNING",f"Delete root admin '{username}'?\n\nThis CANNOT be undone.",parent=win): return
                logit(f"ROOT ADMIN SELF-DELETED: {username}"); del cur[username]; save(cur); DB._reload()
                messagebox.showinfo("Deleted",f"Root admin '{username}' deleted.",parent=win); mon.stop(); win.destroy()
            mkbtn(dc,"  DELETE MY ROOT ACCOUNT  ",del_root,RED,"white",13,14).pack(fill="x",pady=4)
            tk.Frame(dc,bg=RED,height=3).pack(fill="x",pady=(16,0))
    def t_log(f):
        tk.Label(f,text="FULL AUDIT LOG",fg=CYN,bg=BG,font=("Courier New",14,"bold")).pack(anchor="w",padx=20,pady=(12,6))
        txt=tk.Text(f,bg=BG3,fg=CDM,font=("Courier New",8),relief="flat",bd=0,wrap="word")
        sb2=tk.Scrollbar(f,command=txt.yview); txt.configure(yscrollcommand=sb2.set)
        sb2.pack(side="right",fill="y"); txt.pack(fill="both",expand=True,padx=10,pady=(0,10))
        decrypted=_log_dec_all(LOG_FILE)
        if decrypted: txt.insert("end",decrypted)
        txt.see("end"); txt.config(state="disabled")
    tab("USB CONTROL",t_usb); tab("OVERVIEW",t_ov); tab("USERS",t_users); tab("MY ACCOUNT",t_acc); tab("AUDIT LOG",t_log)
    def logout(): logit(f"Logout: {username}"); mon.stop(); win.destroy()
    lo=tk.Label(tbar,text="  LOGOUT  ",bg=BG3,fg=RED,font=("Courier New",11,"bold"),padx=6,pady=10,cursor="hand2")
    lo.pack(side="right"); lo.bind("<Button-1>",lambda e:logout())
    sw("USB CONTROL",t_usb)

